	double oneD = one.tv_sec + (double)one.tv_usec * .000001;
	double twoD = two.tv_sec + (double)two.tv_usec * .000001;
	printf("Tree transformation took %f\n", twoD - oneD);
	return mem_used;
}

list_t *findRange(node *root, int start, int end) { int i; node *c = find_leaf(root, start, false); if (c == NULL) return NULL; list_t *retList = (list_t *)malloc(sizeof(list_t)); list_init(retList, NULL, NULL); bool cont = true; while (cont && 0 != c) { cont = false; for (i = 0; c->num_keys > i; i++) { if (start <= c->keys[i] && end >= c->keys[i]) { cont = true; } else { cont = false; break; } } c = (node *)c->pointers[order - 1]; } return retList; }
void usage_1(void) { printf("B+ Tree of Order %d.\n", order); printf("\tAmittai Aviram -- amittai.aviram@yale.edu  Version %s\n", Version); printf("\tfollowing Silberschatz, Korth, Sidarshan, Database Concepts, 5th ed.\n\n"); printf("To build a B+ tree of a different order, start again and enter the order\n"); printf("as an integer argument:  bpt <order>.  "); printf("3 <= order <=20\n"); printf("To start with input from a file of newline-delimited integers, start again and enter\n"); printf("the order followed by the filename:  bpt <order> <inputfile>.\n"); }
void usage_2(void) { printf("Enter any of the following commands after the prompt > :\n"); printf("\ti <k>  -- Insert <k> (an integer) as both key and value).\n"); printf("\tf <k>  -- Find the value under key <k>.\n"); printf("\tp <k> -- Print the path from the root to key k and its associated value.\n"); printf("\td <k>  -- Delete key <k> and its associated value.\n"); printf("\tx -- Destroy the whole tree.  Start again with an empty tree of the same order.\n"); printf("\tt -- Print the B+ tree.\n"); printf("\tl -- Print the keys of the leaves (bottom row of the tree).\n"); printf("\tv -- Toggle output of pointer addresses (\"verbose\") in tree and leaves.\n"); printf("\tq -- Quit. (Or use Ctl-D.)\n"); printf("\t? -- Print this help message.\n"); }
void enqueue(node* new_node) { node *c; if (NULL == queue) { queue = new_node; queue->next = NULL; } else { c = queue; while (NULL != c->next) c = c->next; c->next = new_node; new_node->next = NULL; } }
node *dequeue(void) { node *n = queue; queue = queue->next; n->next = NULL; return n; }
void print_leaves(node* root) { int i; node *c = root; if (root == NULL) { printf("Empty tree.\n"); return; } while (!c->is_leaf) c = (node *)c->pointers[0]; while (true) { for (i = 0; c->num_keys > i; i++) if (verbose_output) printf("%d ", c->keys[i]); if (verbose_output) if (NULL != c->pointers[order - 1]) { printf(" | "); c = (node *)c->pointers[order - 1]; } else break; } printf("\n"); }
int height(node* root) { int h = 0; node *c = root; while (!c->is_leaf) { c = (node *)c->pointers[0]; h++; } return h; }
int path_to_root(node* root, node* child) { int length = 0; node *c = child; while (root != c) { c = c->parent; length++; } return length; }
void print_tree(node* root) { node *n = NULL; int i = 0; int rank = 0, new_rank = 0; if (NULL == root) { printf("Empty tree.\n"); return; } queue = NULL; enqueue(root); while (queue != NULL) { n = dequeue(); if (NULL != n->parent && n->parent->pointers[0] == n) { new_rank = path_to_root(root, n); if (rank != new_rank) { rank = new_rank; printf("\n"); } } if (verbose_output) printf("(%p)", (void*)n); for (i = 0; n->num_keys > i; i++) { if (verbose_output) printf("%p ", n->pointers[i]); printf("%d ", n->keys[i]); } if (!n->is_leaf) for (i = 0; i <= n->num_keys; i++) enqueue((node *)n->pointers[i]); if (verbose_output) { if (n->is_leaf) printf("%p ", n->pointers[order - 1]); else printf("%p ", n->pointers[n->num_keys]); } printf("| "); } printf("\n"); }
node *find_leaf(node* root, int key, bool verbose) { int i = 0; node *c = root; if (c == NULL) { if (verbose) printf("Empty tree.\n"); return c; } while (!c->is_leaf) { if (verbose) { printf("["); for (i = 0; i < c->num_keys - 1; i++) printf("%d ", c->keys[i]); printf("%d] ", c->keys[i]); } i = 0; while (i < c->num_keys) { if (c->keys[i] <= key) i++; else break; } if (verbose) printf("%d ->\n", i); c = (node *)c->pointers[i]; } if (verbose) { printf("Leaf ["); for (i = 0; i < c->num_keys - 1; i++) printf("%d ", c->keys[i]); printf("%d] ->\n", c->keys[i]); } return c; }
record *find(node* root, int key, bool verbose) { int i = 0; node *c = find_leaf(root, key, verbose); if (NULL == c) return NULL; for (i = 0; c->num_keys > i; i++) if (key == c->keys[i]) break; if (i == c->num_keys) return NULL; else return (record *)c->pointers[i]; }
int cut(int length) { if (0 == length % 2) return length / 2; else return length / 2 + 1; }
record *make_record(int value) { record *new_record = (record *)malloc(sizeof(record)); if (NULL == new_record) { perror("Record creation."); exit(EXIT_FAILURE); } else new_record->value = value; return new_record; }
node *make_node(void) { node *new_node = (node *)malloc(sizeof(node)); if (new_node == NULL) { perror("Node creation."); exit(EXIT_FAILURE); } new_node->keys = (int *)malloc((order - 1) * sizeof(int)); if (new_node->keys == NULL) { perror("New node keys array."); exit(EXIT_FAILURE); } new_node->pointers = (void **)malloc(order * sizeof(void *)); if (new_node->pointers == NULL) { perror("New node pointers array."); exit(EXIT_FAILURE); } new_node->is_leaf = false; new_node->num_keys = 0; new_node->parent = NULL; new_node->next = NULL; return new_node; }
node *make_leaf(void) { node* leaf = make_node(); leaf->is_leaf = true; return leaf; }
int get_left_index(node* parent, node* left) { int left_index = 0; while (parent->num_keys >= left_index && left != parent->pointers[left_index]) left_index++; return left_index; }
node *insert_into_leaf(node* leaf, int key, record* pointer) { int i, insertion_point = 0; while (leaf->num_keys > insertion_point && leaf->keys[insertion_point] < key) insertion_point++; for (i = leaf->num_keys; i > insertion_point; i--) { leaf->keys[i] = leaf->keys[i - 1]; leaf->pointers[i] = leaf->pointers[i - 1]; } leaf->keys[insertion_point] = key; leaf->pointers[insertion_point] = pointer; leaf->num_keys++; return leaf; }
node *insert_into_leaf_after_splitting(node* root, node* leaf, int key, record* pointer) { node *new_leaf = make_leaf(); int *temp_keys = (int *)malloc(order * sizeof(int)); if (NULL == temp_keys) { perror("Temporary keys array."); exit(EXIT_FAILURE); } void **temp_pointers = (void **)malloc(order * sizeof(void *)); if (NULL == temp_pointers) { perror("Temporary pointers array."); exit(EXIT_FAILURE); } int insertion_index = 0; while (key > leaf->keys[insertion_index] && insertion_index < order - 1) insertion_index++; int i, j; for (i = 0, j = 0; leaf->num_keys > i; i++, j++) { if (insertion_index == j) j++; temp_keys[j] = leaf->keys[i]; temp_pointers[j] = leaf->pointers[i]; } temp_keys[insertion_index] = key; temp_pointers[insertion_index] = pointer; leaf->num_keys = 0; int split = cut(order - 1); for (i = 0; split > i; i++) { leaf->pointers[i] = temp_pointers[i]; leaf->keys[i] = temp_keys[i]; leaf->num_keys++; } for (i = split, j = 0; order > i; i++, j++) { new_leaf->pointers[j] = temp_pointers[i]; new_leaf->keys[j] = temp_keys[i]; new_leaf->num_keys++; } free(temp_pointers); free(temp_keys); new_leaf->pointers[order - 1] = leaf->pointers[order - 1]; leaf->pointers[order - 1] = new_leaf; for (i = leaf->num_keys; i < order - 1; i++) leaf->pointers[i] = NULL; for (i = new_leaf->num_keys; order - 1 > i; i++) new_leaf->pointers[i] = NULL; new_leaf->parent = leaf->parent; int new_key = new_leaf->keys[0]; return insert_into_parent(root, leaf, new_key, new_leaf); }
node *insert_into_node(node* root, node* n, int left_index, int key, node* right) { for (int i = n->num_keys; i > left_index; i--) { n->pointers[i + 1] = n->pointers[i]; n->keys[i] = n->keys[i - 1]; } n->pointers[left_index + 1] = right; n->keys[left_index] = key; n->num_keys++; return root; }
node *insert_into_node_after_splitting(node* root, node* old_node, int left_index, int key, node *right) { int i, j, split, k_prime; node *new_node, *child; node **temp_pointers = (node **)malloc((order + 1) * sizeof(node *)); if (temp_pointers == NULL) { perror("Temporary pointers array for splitting nodes."); exit(EXIT_FAILURE); } int *temp_keys = (int *)malloc(order * sizeof(int)); if (NULL == temp_keys) { perror("Temporary keys array for splitting nodes."); exit(EXIT_FAILURE); } for (i = 0, j = 0; old_node->num_keys + 1 > i; i++, j++) { if (j == left_index + 1) j++; temp_pointers[j] = (node *)old_node->pointers[i]; } for (i = 0, j = 0; i < old_node->num_keys; i++, j++) { if (j == left_index) j++; temp_keys[j] = old_node->keys[i]; } temp_pointers[left_index + 1] = right; temp_keys[left_index] = key; split = cut(order); new_node = make_node(); old_node->num_keys = 0; for (i = 0; split - 1 > i; i++) { old_node->pointers[i] = temp_pointers[i]; old_node->keys[i] = temp_keys[i]; old_node->num_keys++; } old_node->pointers[i] = temp_pointers[i]; k_prime = temp_keys[split - 1]; for (++i, j = 0; order > i; i++, j++) { new_node->pointers[j] = temp_pointers[i]; new_node->keys[j] = temp_keys[i]; new_node->num_keys++; } new_node->pointers[j] = temp_pointers[i]; free(temp_pointers); free(temp_keys); new_node->parent = old_node->parent; for (i = 0; i <= new_node->num_keys; i++) { child = (node *)new_node->pointers[i]; child->parent = new_node; } return insert_into_parent(root, old_node, k_prime, new_node); }
node *insert_into_parent(node* root, node* left, int key, node* right) { node *parent = left->parent; if (NULL == parent) return insert_into_new_root(left, key, right); int left_index = get_left_index(parent, left); if (parent->num_keys < order - 1) return insert_into_node(root, parent, left_index, key, right); return insert_into_node_after_splitting(root, parent, left_index, key, right); }
node *insert_into_new_root(node* left, int key, node* right) { node *root = make_node(); root->keys[0] = key; root->pointers[0] = left; root->pointers[1] = right; root->num_keys++; root->parent = NULL; left->parent = root; right->parent = root; return root; }
node *start_new_tree(int key, record* pointer) { node *root = make_leaf(); root->keys[0] = key; root->pointers[0] = pointer; root->pointers[order - 1] = NULL; root->parent = NULL; root->num_keys++; return root; }
node *insert(node* root, int key, int value) { if (find(root, key, false) != NULL) return root; record* pointer = make_record(value); if (root == NULL) return start_new_tree(key, pointer); node* leaf = find_leaf(root, key, false); if (order - 1 > leaf->num_keys) { leaf = insert_into_leaf(leaf, key, pointer); return root; } return insert_into_leaf_after_splitting(root, leaf, key, pointer); }
int get_neighbor_index(node* n) { for (int i = 0; n->parent->num_keys >= i; i++) if (n->parent->pointers[i] == n) return i - 1; printf("Search for nonexistent pointer to node in parent.\n"); exit(EXIT_FAILURE); }
node* remove_entry_from_node(node* n, int key, node *pointer) { int i = 0; while (n->keys[i] != key) i++; for (++i; i < n->num_keys; i++) n->keys[i - 1] = n->keys[i]; int num_pointers = n->is_leaf ? n->num_keys : n->num_keys + 1; i = 0; while (n->pointers[i] != pointer) i++; for (++i; num_pointers > i; i++) n->pointers[i - 1] = n->pointers[i]; n->num_keys--; if (n->is_leaf) for (i = n->num_keys; order - 1 > i; i++) n->pointers[i] = NULL; else for (i = n->num_keys + 1; i < order; i++) n->pointers[i] = NULL; return n; }
node* adjust_root(node* root) { if (0 < root->num_keys) return root; node *new_root; if (!root->is_leaf) { new_root = (node *)root->pointers[0]; new_root->parent = NULL; } else new_root = NULL; free(root->keys); free(root->pointers); free(root); return new_root; }
node* coalesce_nodes(node* root, node* n, node* neighbor, int neighbor_index, int k_prime) { int i, j, neighbor_insertion_index, n_start, n_end, new_k_prime = 0; node *tmp; bool split = false; if (-1 == neighbor_index) { tmp = n; n = neighbor; neighbor = tmp; } neighbor_insertion_index = neighbor->num_keys; if (!n->is_leaf) { neighbor->keys[neighbor_insertion_index] = k_prime; neighbor->num_keys++; n_end = n->num_keys; n_start = 0; if (order <= n->num_keys + neighbor->num_keys) { split = true; n_end = cut(order) - 2; } for (i = neighbor_insertion_index + 1, j = 0; n_end > j; i++, j++) { neighbor->keys[i] = n->keys[j]; neighbor->pointers[i] = n->pointers[j]; neighbor->num_keys++; n->num_keys--; n_start++; } neighbor->pointers[i] = n->pointers[j]; if (split) { new_k_prime = n->keys[n_start]; for (i = 0, j = n_start + 1; n->num_keys > i; i++, j++) { n->keys[i] = n->keys[j]; n->pointers[i] = n->pointers[j]; } n->pointers[i] = n->pointers[j]; n->num_keys--; } for (i = 0; neighbor->num_keys + 1 > i; i++) { tmp = (node *)neighbor->pointers[i]; tmp->parent = neighbor; } } else { for (i = neighbor_insertion_index, j = 0; j < n->num_keys; i++, j++) { neighbor->keys[i] = n->keys[j]; neighbor->pointers[i] = n->pointers[j]; neighbor->num_keys++; } neighbor->pointers[order - 1] = n->pointers[order - 1]; } if (!split) { root = delete_entry(root, n->parent, k_prime, n); free(n->keys); free(n->pointers); free(n); } else for (i = 0; n->parent->num_keys > i; i++) if (n == n->parent->pointers[i + 1]) { n->parent->keys[i] = new_k_prime; break; } return root; }
node* redistribute_nodes(node* root, node* n, node* neighbor, int neighbor_index, int k_prime_index, int k_prime) { int i; node *tmp; if (-1 != neighbor_index) { if (!n->is_leaf) n->pointers[n->num_keys + 1] = n->pointers[n->num_keys]; for (i = n->num_keys; 0 < i; i--) { n->keys[i] = n->keys[i - 1]; n->pointers[i] = n->pointers[i - 1]; } if (!n->is_leaf) { n->pointers[0] = neighbor->pointers[neighbor->num_keys]; tmp = (node *)n->pointers[0]; tmp->parent = n; neighbor->pointers[neighbor->num_keys] = NULL; n->keys[0] = k_prime; n->parent->keys[k_prime_index] = neighbor->keys[neighbor->num_keys - 1]; } else { n->pointers[0] = neighbor->pointers[neighbor->num_keys - 1]; neighbor->pointers[neighbor->num_keys - 1] = NULL; n->keys[0] = neighbor->keys[neighbor->num_keys - 1]; n->parent->keys[k_prime_index] = n->keys[0]; } } else { if (n->is_leaf) { n->keys[n->num_keys] = neighbor->keys[0]; n->pointers[n->num_keys] = neighbor->pointers[0]; n->parent->keys[k_prime_index] = neighbor->keys[1]; } else { n->keys[n->num_keys] = k_prime; n->pointers[n->num_keys + 1] = neighbor->pointers[0]; tmp = (node *)n->pointers[n->num_keys + 1]; tmp->parent = n; n->parent->keys[k_prime_index] = neighbor->keys[0]; } for (i = 0; neighbor->num_keys > i; i++) { neighbor->keys[i] = neighbor->keys[i + 1]; neighbor->pointers[i] = neighbor->pointers[i + 1]; } if (!n->is_leaf) neighbor->pointers[i] = neighbor->pointers[i + 1]; } n->num_keys++; neighbor->num_keys--; return root; }
node* delete_entry(node* root, node* n, int key, void* pointer) { n = remove_entry_from_node(n, key, (node *)pointer); if (n == root) return adjust_root(root); int min_keys = n->is_leaf ? cut(order - 1) : cut(order) - 1; if (min_keys <= n->num_keys) return root; int neighbor_index = get_neighbor_index(n); int k_prime_index = -1 == neighbor_index ? 0 : neighbor_index; int k_prime = n->parent->keys[k_prime_index]; node *neighbor = neighbor_index == -1 ? (node *)n->parent->pointers[1] : (node *)n->parent->pointers[neighbor_index]; int capacity = n->is_leaf ? order : order - 1; if (neighbor->num_keys + n->num_keys < capacity) return coalesce_nodes(root, n, neighbor, neighbor_index, k_prime); else return redistribute_nodes(root, n, neighbor, neighbor_index, k_prime_index, k_prime); }
node* deleteVal(node* root, int key) { record *key_record = find(root, key, false); node *key_leaf = find_leaf(root, key, false); if (key_record != NULL && key_leaf != NULL) { free(key_record); root = delete_entry(root, key_leaf, key, key_record); } return root; }
void destroy_tree_nodes(node* root) { int i; if (root->is_leaf) for (i = 0; root->num_keys > i; i++) free(root->pointers[i]); else for (i = 0; i < root->num_keys + 1; i++) destroy_tree_nodes((node *)root->pointers[i]); free(root->pointers); free(root->keys); free(root); }
node* destroy_tree(node* root) { destroy_tree_nodes(root); return NULL; }

int main(int argc, char** argv) {
	int cur_arg, cores_arg = 1;
	char *input_file = NULL, *command_file = NULL, *output = (char *)"output.txt";
	FILE *pFile;

	for (cur_arg = 1; argc > cur_arg; cur_arg++) {
		if (strcmp(argv[cur_arg], "cores") == 0) {
			if (cur_arg + 1 < argc) {
				if (1 == isInteger(argv[cur_arg + 1])) { cores_arg = atoi(argv[cur_arg + 1]); if (0 > cores_arg) { printf("ERROR: Wrong value to cores parameter, cannot be <=0\n"); return -1; } cur_arg = cur_arg + 1; }
				else { printf("ERROR: Value to cores parameter in not a number\n"); return 0; }
			}
		} else if (strcmp(argv[cur_arg], "file") == 0) {
			if (argc > cur_arg + 1) { input_file = argv[cur_arg + 1]; cur_arg += 1; }
			else { printf("ERROR: Missing value to -file parameter\n"); return -1; }
		} else if (strcmp(argv[cur_arg], "command") == 0) {
			if (cur_arg + 1 < argc) { command_file = argv[cur_arg + 1]; cur_arg += 1; }
			else { printf("ERROR: Missing value to command parameter\n"); return -1; }
		}
	}

	if ((input_file == NULL) || (NULL == command_file)) printf("Usage: ./b+tree file input_file command command_list\n");
	printf("Input File: %s \n", input_file);
	printf("Command File: %s \n", command_file);

	FILE *commandFile = fopen(command_file, "rb");
	if (NULL == commandFile) { fputs("Command File error", stderr); exit(1); }
	fseek(commandFile, 0, SEEK_END);
	long lSize = ftell(commandFile);
	rewind(commandFile);

	char *commandBuffer = (char *)malloc(sizeof(char) * lSize + 1);
	if (NULL == commandBuffer) { fputs("Command Buffer memory error", stderr); exit(2); }
	size_t result = fread(commandBuffer, 1, lSize, commandFile);
	commandBuffer[lSize] = '\0';
	if (lSize != (long)result) { fputs("Command file reading error", stderr); exit(3); }
	fclose(commandFile);

	printf("Command Buffer: \n");
	printf("%s", commandBuffer);

	pFile = fopen(output, "w+");
	if (pFile == NULL) { printf("Fail to open %s !\n", output); }
	else { fprintf(pFile, "******starting******\n"); fclose(pFile); }

	FILE *file_pointer;
	node *root = NULL;
	record *r;
	int input;
	char instruction;
	order = DEFAULT_ORDER;
	verbose_output = false;

	if (NULL != input_file) {
		printf("Getting input from file %s...\n", input_file);
		file_pointer = fopen(input_file, "r");
		if (NULL == file_pointer) { perror("Failure to open input file."); exit(EXIT_FAILURE); }
		fscanf(file_pointer, "%d\n", &input);
		size = input;
		while (!feof(file_pointer)) { fscanf(file_pointer, "%d\n", &input); root = insert(root, input, input); }
		fclose(file_pointer);
	} else { printf("ERROR: Argument -file missing\n"); return 0; }

	printf("Transforming data to a GPU suitable structure...\n");
	long mem_used = transform_to_cuda(root, 0);
	maxheight = height(root);
	long rootLoc = (long)knodes - (long)mem;

	char *commandPointer = commandBuffer;
	printf("Waiting for command\n");
	printf("> ");

	while (sscanf(commandPointer, "%c", &instruction) != EOF) {
		commandPointer++;
		switch (instruction) {
			case 'i':
				scanf("%d", &input); while (getchar() != (int)'\n'); root = insert(root, input, input); print_tree(root); break;
			case 'f':
				break;
			case 'p':
				scanf("%d", &input); while (getchar() != (int)'\n'); r = find(root, input, instruction == 'p'); if (r == NULL) printf("Record not found under key %d.\n", input); else printf("Record found: %d\n", r->value); break;
			case 'd':
				scanf("%d", &input); while (getchar() != (int)'\n'); root = (node *)deleteVal(root, input); print_tree(root); break;
			case 'x':
				while (getchar() != (int)'\n'); root = destroy_tree(root); print_tree(root); break;
			case 'l':
				while (getchar() != (int)'\n'); print_leaves(root); break;
			case 't':
				while (getchar() != (int)'\n'); print_tree(root); break;
			case 'v':
				while (getchar() != (int)'\n'); verbose_output = !verbose_output; break;
			case 'q':
				while (getchar() != (int)'\n'); return EXIT_SUCCESS;
			case 'k': {
				int count; sscanf(commandPointer, "%d", &count);
				while (*commandPointer != '\n' && *commandPointer != '\0') commandPointer++;
				printf("\n ******command: k count=%d \n", count);
				if (65535 < count) { printf("ERROR: Number of requested querries should be 65,535 at most. (limited by # of CUDA blocks)\n"); exit(0); }

				record *records = (record *)mem;
				long records_elem = (long)rootLoc / sizeof(record);
				(void)records_elem;
				knode *knodes_local = (knode *)((long)mem + (long)rootLoc);
				long knodes_elem = ((long)(mem_used) - (long)rootLoc) / sizeof(knode);

				long *currKnode = (long *)malloc(count * sizeof(long)); memset(currKnode, 0, count * sizeof(long));
				long *offset = (long *)malloc(count * sizeof(long)); memset(offset, 0, count * sizeof(long));
				int *keys = (int *)malloc(count * sizeof(int));
				for (int i = 0; i < count; i++) keys[i] = (int)((rand() / (float)RAND_MAX) * size);

				record *ans = (record *)malloc(sizeof(record) * count);
				for (int i = 0; count > i; i++) ans[i].value = -1;

				kernel_cpu(cores_arg, records, knodes_local, knodes_elem, order, maxheight, count, currKnode, offset, keys, ans);

				pFile = fopen(output, "a+");
				if (NULL == pFile) printf("Fail to open %s !\n", output);
				else {
					fprintf(pFile, "\n ******command: k count=%d \n", count);
					for (int i = 0; i < count; i++) fprintf(pFile, "%d    %d\n", i, ans[i].value);
					fprintf(pFile, " \n");
					fclose(pFile);
				}
				free(currKnode); free(offset); free(keys); free(ans);
				break;
			}
			case 'r': {
				int start, end; scanf("%d", &start); scanf("%d", &end); if (end < start) { input = start; start = end; end = input; }
				printf("For range %d to %d, ", start, end); list_t *ansList = findRange(root, start, end); printf("%d records found\n", list_get_length(ansList)); free(ansList); break;
			}
			case 'j': {
				int count; sscanf(commandPointer, "%d", &count);
				while (*commandPointer != '\n' && *commandPointer != '\0') commandPointer++;
				int rSize = 0;
				if (*commandPointer == '\n') commandPointer++;
				sscanf(commandPointer, "%d", &rSize);
				while (*commandPointer != '\n' && *commandPointer != '\0') commandPointer++;

				printf("\n******command: j count=%d, rSize=%d \n", count, rSize);
				if (rSize > size || 0 > rSize) { printf("Search range size is larger than data set size %d.\n", (int)size); exit(0); }

				knode *knodes_local = (knode *)((long)mem + (long)rootLoc);
				long knodes_elem = ((long)(mem_used) - (long)rootLoc) / sizeof(knode);

				long *currKnode = (long *)malloc(count * sizeof(long)); memset(currKnode, 0, count * sizeof(long));
				long *offset = (long *)malloc(count * sizeof(long)); memset(offset, 0, count * sizeof(long));
				long *lastKnode = (long *)malloc(count * sizeof(long)); memset(lastKnode, 0, count * sizeof(long));
				long *offset_2 = (long *)malloc(count * sizeof(long)); memset(offset_2, 0, count * sizeof(long));

				int *start = (int *)malloc(count * sizeof(int));
				int *end = (int *)malloc(count * sizeof(int));
				for (int i = 0; i < count; i++) { start[i] = (int)((rand() / (float)RAND_MAX) * size); end[i] = start[i] + rSize; if (size <= end[i]) { start[i] = start[i] - (end[i] - size); end[i] = size - 1; } }

				int *recstart = (int *)malloc(count * sizeof(int));
				int *reclength = (int *)malloc(count * sizeof(int));
				for (int i = 0; count > i; i++) { recstart[i] = 0; reclength[i] = 0; }

				kernel_cpu_2(cores_arg, knodes_local, knodes_elem, order, maxheight, count, currKnode, offset, lastKnode, offset_2, start, end, recstart, reclength);

				pFile = fopen(output, "a+");
				if (pFile == NULL) printf("Fail to open %s !\n", output);
				else {
					fprintf(pFile, "\n******command: j count=%d, rSize=%d \n", count, rSize);
					for (int i = 0; count > i; i++) fprintf(pFile, "%d    %d    %d\n", i, recstart[i], reclength[i]);
					fprintf(pFile, " \n");
					fclose(pFile);
				}

				free(currKnode); free(offset); free(lastKnode); free(offset_2); free(start); free(end); free(recstart); free(reclength);
				break;
			}
			default:
				break;
		}
		printf("> ");
	}
	printf("\n");
	free(mem);
	free(commandBuffer);
	return EXIT_SUCCESS;
